    val n = arr.size
    val rng = Random(seed)
    val popSize = minOf(20, n)
    val generations = 100
    val mutationRate = 0.1

    var population = IntArray(popSize) { rng.nextInt(n) }

    var bestIdx = population[0]
    for (idx in population) {
        if (arr[idx] < arr[bestIdx]) bestIdx = idx
    }

    repeat(generations) {
        val newPop = IntArray(popSize) {
            val a = population[rng.nextInt(popSize)]
            val b = population[rng.nextInt(popSize)]
            if (arr[a] <= arr[b]) a else b
        }

        val offspring = IntArray(popSize)
        var i = 0
        while (i + 1 < popSize) {
            if (rng.nextDouble() < 0.7) {
                offspring[i] = newPop[i]
                offspring[i + 1] = newPop[i + 1]
            } else {
                offspring[i] = newPop[i + 1]
                offspring[i + 1] = newPop[i]
            }
            i += 2
        }
        if (popSize % 2 != 0) {
            offspring[popSize - 1] = newPop[popSize - 1]
        }

        for (j in 0 until popSize) {
            if (rng.nextDouble() < mutationRate) {
                offspring[j] = rng.nextInt(n)
            }
        }

        population = offspring

        for (idx in population) {
            if (arr[idx] < arr[bestIdx]) bestIdx = idx
        }
    }

    return arr[bestIdx]
}

pub fn genetic_algorithm(arr: &[i32], seed: u64) -> i32 {
    if arr.is_empty() {
        return 0;
    }
    if arr.len() == 1 {
        return arr[0];
    }

    let n = arr.len();
    let pop_size = std::cmp::min(20, n);
    let generations = 100;
    let mutation_rate = 0.1_f64;

    let mut state = seed;
    let mut next_rand = || -> f64 {
        state = state.wrapping_mul(6364136223846793005).wrapping_add(1442695040888963407);
        (state >> 33) as f64 / (1u64 << 31) as f64
    };
    let mut next_int = |max: usize| -> usize {
        let r = next_rand();
        (r * max as f64) as usize % max
    };

    let mut population: Vec<usize> = (0..pop_size).map(|_| next_int(n)).collect();

    let mut best_idx = population[0];
    for &idx in &population {
        if arr[idx] < arr[best_idx] {
            best_idx = idx;
        }
    }

    for _ in 0..generations {
        let mut new_pop = Vec::with_capacity(pop_size);
        for _ in 0..pop_size {
            let a = population[next_int(pop_size)];
            let b = population[next_int(pop_size)];
            new_pop.push(if arr[a] <= arr[b] { a } else { b });
        }

        let mut offspring = vec![0usize; pop_size];
        let mut i = 0;
        while i + 1 < pop_size {
            if next_rand() < 0.7 {
                offspring[i] = new_pop[i];
                offspring[i + 1] = new_pop[i + 1];
            } else {
                offspring[i] = new_pop[i + 1];
                offspring[i + 1] = new_pop[i];
            }
            i += 2;
        }
        if pop_size % 2 != 0 {
            offspring[pop_size - 1] = new_pop[pop_size - 1];
        }

        for j in 0..pop_size {
            if next_rand() < mutation_rate {
                offspring[j] = next_int(n);
            }
        }

        population = offspring;

        for &idx in &population {
            if arr[idx] < arr[best_idx] {
                best_idx = idx;
            }
        }
    }

    arr[best_idx]
}

object GeneticAlgorithm {

  def geneticAlgorithm(arr: Array[Int], seed: Int): Int = {
    if (arr.isEmpty) return 0
    if (arr.length == 1) return arr(0)

    val n = arr.length
    val rng = new scala.util.Random(seed)
    val popSize = math.min(20, n)
    val generations = 100
    val mutationRate = 0.1

    var population = Array.fill(popSize)(rng.nextInt(n))

    var bestIdx = population.minBy(i => arr(i))

    for (_ <- 0 until generations) {
      val newPop = Array.fill(popSize) {
        val a = population(rng.nextInt(popSize))
        val b = population(rng.nextInt(popSize))
        if (arr(a) <= arr(b)) a else b
      }

      val offspring = new Array[Int](popSize)
      var i = 0
      while (i + 1 < popSize) {
        if (rng.nextDouble() < 0.7) {
          offspring(i) = newPop(i)
          offspring(i + 1) = newPop(i + 1)
        } else {
          offspring(i) = newPop(i + 1)
          offspring(i + 1) = newPop(i)
        }
        i += 2
      }
      if (popSize % 2 != 0) {
        offspring(popSize - 1) = newPop(popSize - 1)
      }

      for (j <- 0 until popSize) {
        if (rng.nextDouble() < mutationRate) {
          offspring(j) = rng.nextInt(n)
        }
      }

      population = offspring

      val genBest = population.minBy(idx => arr(idx))
      if (arr(genBest) < arr(bestIdx)) bestIdx = genBest
    }

    arr(bestIdx)
  }
}

